// ==================== COMPONENTS ====================

// Login Component
function Login({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const { data, error } = await supabase.auth.signInWithPassword({ email, password });

    if (error) {
      setError(error.message);
    } else {
      onLogin(data.user);
    }
    setLoading(false);
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <h2>Constitutional Reform Platform</h2>
        <p>Sign in to submit your proposals</p>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          <button type="submit" disabled={loading}>{loading ? 'Loading...' : 'Sign In'}</button>
        </form>
        <p>Don't have an account? <Link to="/signup">Sign Up</Link></p>
      </div>
    </div>
  );
}

// Signup Component
function Signup({ onSignup }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [province, setProvince] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const provinces = ['Kinshasa', 'Kongo Central', 'Haut-Katanga', 'Lualaba', 'Nord-Kivu', 'Sud-Kivu', 'Ituri', 'Equateur', 'Mongala', 'Nord-Ubangi', 'Sud-Ubangi', 'Tshopo', 'Bas-Uele', 'Haut-Uele', 'Mai-Ndombe', 'Kwilu', 'Kwango', 'Kasaï', 'Kasaï-Central', 'Kasaï-Oriental', 'Lomami', 'Sankuru', 'Maniema', 'Tanganyika', 'Haut-Lomami', 'Lualaba'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: { data: { full_name: fullName, province, role: 'citizen' } }
    });

    if (error) {
      setError(error.message);
    } else {
      // Create profile in profiles table
      if (data.user) {
        await supabase.from('profiles').insert([{
          id: data.user.id,
          email: email,
          full_name: fullName,
          province: province,
          role: 'citizen'
        }]);
      }
      onSignup(data.user);
    }
    setLoading(false);
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <h2>Create Account</h2>
        <p>Join the constitutional reform consultation</p>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Full Name" value={fullName} onChange={(e) => setFullName(e.target.value)} required />
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
          <input type="password" placeholder="Password (min 6 characters)" value={password} onChange={(e) => setPassword(e.target.value)} required />
          <select value={province} onChange={(e) => setProvince(e.target.value)} required>
            <option value="">Select Province</option>
            {provinces.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
          <button type="submit" disabled={loading}>{loading ? 'Creating Account...' : 'Sign Up'}</button>
        </form>
        <p>Already have an account? <Link to="/login">Sign In</Link></p>
      </div>
    </div>
  );
}

