// Dashboard Component - Submit Proposals
function Dashboard({ user }) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [imageFile, setImageFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [proposals, setProposals] = useState([]);
  const [message, setMessage] = useState('');

  useEffect(() => {
    fetchProposals();
  }, []);

  const fetchProposals = async () => {
    const { data } = await supabase
      .from('proposals')
      .select('*')
      .order('created_at', { ascending: false })
      .limit(10);
    if (data) setProposals(data);
  };

  const handleImageUpload = async (file) => {
    if (!file) return null;
    const fileExt = file.name.split('.').pop();
    const fileName = `${Date.now()}.${fileExt}`;
    const { data, error } = await supabase.storage
      .from('proposal-images')
      .upload(fileName, file);
    if (error) return null;
    const { data: { publicUrl } } = supabase.storage
      .from('proposal-images')
      .getPublicUrl(fileName);
    return publicUrl;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    let imageUrl = null;
    if (imageFile) {
      imageUrl = await handleImageUpload(imageFile);
    }

    const { error } = await supabase.from('proposals').insert([{
      user_id: user.id,
      title,
      content,
      image_urls: imageUrl ? [imageUrl] : [],
      status: 'pending'
    }]);

    if (error) {
      setMessage('Error submitting proposal: ' + error.message);
    } else {
      setMessage('Proposal submitted successfully!');
      setTitle('');
      setContent('');
      setImageFile(null);
      fetchProposals();
    }
    setLoading(false);
  };

  return (
    <div className="dashboard">
      <div className="proposal-form">
        <h2>Submit Your Constitutional Reform Proposal</h2>
        {message && <div className="success-message">{message}</div>}
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Proposal Title" value={title} onChange={(e) => setTitle(e.target.value)} required />
          <textarea placeholder="Write your proposal details here..." rows="8" value={content} onChange={(e) => setContent(e.target.value)} required />
          <input type="file" accept="image/*" onChange={(e) => setImageFile(e.target.files[0])} />
          <button type="submit" disabled={loading}>{loading ? 'Submitting...' : 'Submit Proposal'}</button>
        </form>
      </div>
      <div className="proposals-list">
        <h3>Recent Proposals</h3>
        {proposals.map(p => (
          <div key={p.id} className="proposal-card">
            <h4>{p.title}</h4>
            <p>{p.content.substring(0, 200)}...</p>
            {p.image_urls && p.image_urls[0] && <img src={p.image_urls[0]} alt="Proposal" />}
            <small>Submitted: {new Date(p.created_at).toLocaleDateString()}</small>
          </div>
        ))}
      </div>
    </div>
  );
}

// Main App Component
function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user || null);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null);
    });

    return () => subscription.unsubscribe();
  }, []);

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <BrowserRouter>
      <nav className="navbar">
        <div className="nav-brand">🇨🇩 Constitutional Reform Platform</div>
        <div className="nav-links">
          <Link to="/">Home</Link>
          {user && <Link to="/dashboard">Dashboard</Link>}
          {user ? (
            <button onClick={() => supabase.auth.signOut()}>Sign Out</button>
          ) : (
            <Link to="/login">Sign In</Link>
          )}
        </div>
      </nav>
      <Routes>
        <Route path="/" element={<Homepage user={user} />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <Login onLogin={setUser} />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <Signup onSignup={setUser} />} />
        <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
